    struct GatedSnapshotRuntimeStore {
        inner: InMemoryRuntimeStore,
        hidden_snapshot_loads: AtomicUsize,
        fail_snapshot_loads: AtomicBool,
        fail_snapshot_commits: AtomicBool,
        snapshot_commit_count: AtomicUsize,
        fail_snapshot_commit_ordinal: AtomicUsize,
        fail_snapshot_replaces: AtomicBool,
        fail_machine_lifecycle_commits: AtomicBool,
        session_snapshot_overrides: Mutex<HashMap<LogicalRuntimeId, Vec<u8>>>,
        replace_snapshot_interlopers: Mutex<HashMap<LogicalRuntimeId, Vec<u8>>>,
        clear_snapshot_interlopers: Mutex<HashMap<LogicalRuntimeId, Vec<u8>>>,
        input_state_load_errors: Mutex<HashSet<LogicalRuntimeId>>,
        boundary_commits: Mutex<Vec<meerkat_core::lifecycle::RunBoundaryReceipt>>,
    }

    impl GatedSnapshotRuntimeStore {
        fn new() -> Self {
            Self {
                inner: InMemoryRuntimeStore::new(),
                hidden_snapshot_loads: AtomicUsize::new(0),
                fail_snapshot_loads: AtomicBool::new(false),
                fail_snapshot_commits: AtomicBool::new(false),
                snapshot_commit_count: AtomicUsize::new(0),
                fail_snapshot_commit_ordinal: AtomicUsize::new(usize::MAX),
                fail_snapshot_replaces: AtomicBool::new(false),
                fail_machine_lifecycle_commits: AtomicBool::new(false),
                session_snapshot_overrides: Mutex::new(HashMap::new()),
                replace_snapshot_interlopers: Mutex::new(HashMap::new()),
                clear_snapshot_interlopers: Mutex::new(HashMap::new()),
                input_state_load_errors: Mutex::new(HashSet::new()),
                boundary_commits: Mutex::new(Vec::new()),
            }
        }

        fn set_fail_snapshot_commits(&self, fail: bool) {
            self.fail_snapshot_commits.store(fail, Ordering::Release);
        }

        fn set_fail_snapshot_loads(&self, fail: bool) {
            self.fail_snapshot_loads.store(fail, Ordering::Release);
        }

        fn fail_snapshot_commit_in(&self, commits_from_now: usize) {
            assert!(commits_from_now > 0);
            let target = self
                .snapshot_commit_count
                .load(Ordering::Acquire)
                .saturating_add(commits_from_now);
            self.fail_snapshot_commit_ordinal
                .store(target, Ordering::Release);
        }

        fn set_fail_snapshot_replaces(&self, fail: bool) {
            self.fail_snapshot_replaces.store(fail, Ordering::Release);
        }

        fn set_fail_machine_lifecycle_commits(&self, fail: bool) {
            self.fail_machine_lifecycle_commits
                .store(fail, Ordering::Release);
        }

        fn hide_next_session_snapshot_loads(&self, count: usize) {
            self.hidden_snapshot_loads.store(count, Ordering::Release);
        }

        fn should_hide_session_snapshot_load(&self) -> bool {
            let mut remaining = self.hidden_snapshot_loads.load(Ordering::Acquire);
            while remaining > 0 {
                match self.hidden_snapshot_loads.compare_exchange(
                    remaining,
                    remaining - 1,
                    Ordering::AcqRel,
                    Ordering::Acquire,
                ) {
                    Ok(_) => return true,
                    Err(current) => remaining = current,
                }
            }
            false
        }

        async fn boundary_commits(&self) -> Vec<meerkat_core::lifecycle::RunBoundaryReceipt> {
            self.boundary_commits.lock().await.clone()
        }

        async fn reset_boundary_commits(&self) {
            self.boundary_commits.lock().await.clear();
        }

        async fn override_session_snapshot(&self, runtime_id: LogicalRuntimeId, snapshot: Vec<u8>) {
            self.session_snapshot_overrides
                .lock()
                .await
                .insert(runtime_id, snapshot);
        }

        async fn interlope_before_snapshot_replace(
            &self,
            runtime_id: LogicalRuntimeId,
            snapshot: Vec<u8>,
        ) {
            self.replace_snapshot_interlopers
                .lock()
                .await
                .insert(runtime_id, snapshot);
        }

        async fn interlope_before_snapshot_clear(
            &self,
            runtime_id: LogicalRuntimeId,
            snapshot: Vec<u8>,
        ) {
            self.clear_snapshot_interlopers
                .lock()
                .await
                .insert(runtime_id, snapshot);
        }

        async fn fail_input_state_load_for(&self, runtime_id: LogicalRuntimeId) {
            self.input_state_load_errors.lock().await.insert(runtime_id);
        }
    }

    #[async_trait::async_trait]
    impl RuntimeStore for GatedSnapshotRuntimeStore {
        fn supports_compaction_projection_outbox(&self) -> bool {
            self.inner.supports_compaction_projection_outbox()
        }

        async fn observe_machine_lifecycle(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<
            meerkat_runtime::store::MachineLifecycleObservation,
            meerkat_runtime::store::RuntimeStoreError,
        > {
            self.inner.observe_machine_lifecycle(runtime_id).await
        }

        async fn compare_and_swap_machine_lifecycle(
            &self,
            runtime_id: &LogicalRuntimeId,
            expected: meerkat_runtime::store::MachineLifecycleExpectedVersion,
            replacement: meerkat_runtime::store::MachineLifecycleCommit,
        ) -> Result<
            meerkat_runtime::store::MachineLifecycleCasOutcome,
            meerkat_runtime::store::RuntimeStoreError,
        > {
            if self.fail_machine_lifecycle_commits.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    "synthetic machine lifecycle commit failure".to_string(),
                ));
            }
            self.inner
                .compare_and_swap_machine_lifecycle(runtime_id, expected, replacement)
                .await
        }

        async fn commit_session_snapshot(
            &self,
            runtime_id: &LogicalRuntimeId,
            session_delta: meerkat_runtime::store::SessionDelta,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            let ordinal = self
                .snapshot_commit_count
                .fetch_add(1, Ordering::AcqRel)
                .saturating_add(1);
            if self.fail_snapshot_commits.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    "synthetic runtime snapshot commit failure".to_string(),
                ));
            }
            if self
                .fail_snapshot_commit_ordinal
                .compare_exchange(ordinal, usize::MAX, Ordering::AcqRel, Ordering::Acquire)
                .is_ok()
            {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    format!("synthetic runtime snapshot commit failure at ordinal {ordinal}"),
                ));
            }
            if let Some(interloper) = self
                .replace_snapshot_interlopers
                .lock()
                .await
                .remove(runtime_id)
            {
                self.inner
                    .commit_session_snapshot(
                        runtime_id,
                        SessionDelta {
                            session_snapshot: interloper,
                        },
                    )
                    .await?;
            }
            self.inner
                .commit_session_snapshot(runtime_id, session_delta)
                .await
        }

        async fn commit_session_transcript_rewrite_snapshot(
            &self,
            runtime_id: &LogicalRuntimeId,
            session_delta: meerkat_runtime::store::SessionDelta,
            commit: &meerkat_core::TranscriptRewriteCommit,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            if self.fail_snapshot_commits.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    "synthetic runtime snapshot commit failure".to_string(),
                ));
            }
            self.inner
                .commit_session_transcript_rewrite_snapshot(runtime_id, session_delta, commit)
                .await
        }

        async fn atomic_apply(
            &self,
            runtime_id: &LogicalRuntimeId,
            session_delta: Option<meerkat_runtime::store::SessionDelta>,
            receipt: meerkat_core::lifecycle::RunBoundaryReceipt,
            input_updates: Vec<InputStatePersistenceRecord>,
            session_store_key: Option<SessionId>,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            self.inner
                .atomic_apply(
                    runtime_id,
                    session_delta,
                    receipt,
                    input_updates,
                    session_store_key,
                )
                .await
        }

        async fn load_input_states(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<Vec<StoredInputState>, meerkat_runtime::store::RuntimeStoreError> {
            if self
                .input_state_load_errors
                .lock()
                .await
                .contains(runtime_id)
            {
                return Err(meerkat_runtime::store::RuntimeStoreError::ReadFailed(
                    "synthetic legacy input-state load failure".to_string(),
                ));
            }
            self.inner.load_input_states(runtime_id).await
        }

        async fn load_boundary_receipt(
            &self,
            runtime_id: &LogicalRuntimeId,
            run_id: &RunId,
            sequence: u64,
        ) -> Result<
            Option<meerkat_core::lifecycle::RunBoundaryReceipt>,
            meerkat_runtime::store::RuntimeStoreError,
        > {
            self.inner
                .load_boundary_receipt(runtime_id, run_id, sequence)
                .await
        }

        async fn load_session_snapshot(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<Option<Vec<u8>>, meerkat_runtime::store::RuntimeStoreError> {
            if self.fail_snapshot_loads.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::ReadFailed(
                    "synthetic runtime snapshot transport failure".to_string(),
                ));
            }
            if self.should_hide_session_snapshot_load() {
                return Ok(None);
            }
            if let Some(snapshot) = self
                .session_snapshot_overrides
                .lock()
                .await
                .get(runtime_id)
                .cloned()
            {
                return Ok(Some(snapshot));
            }
            self.inner.load_session_snapshot(runtime_id).await
        }

        async fn load_pending_compaction_projections(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<
            Vec<meerkat_core::CompactionProjectionIntent>,
            meerkat_runtime::store::RuntimeStoreError,
        > {
            self.inner
                .load_pending_compaction_projections(runtime_id)
                .await
        }

        async fn mark_compaction_projection_finalized(
            &self,
            runtime_id: &LogicalRuntimeId,
            projection: &meerkat_core::CompactionProjectionId,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            self.inner
                .mark_compaction_projection_finalized(runtime_id, projection)
                .await
        }

        async fn clear_session_snapshot(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            if let Some(interloper) = self
                .clear_snapshot_interlopers
                .lock()
                .await
                .remove(runtime_id)
            {
                self.inner
                    .commit_session_snapshot(
                        runtime_id,
                        SessionDelta {
                            session_snapshot: interloper,
                        },
                    )
                    .await?;
            }
            self.session_snapshot_overrides
                .lock()
                .await
                .remove(runtime_id);
            self.inner.clear_session_snapshot(runtime_id).await
        }

        async fn replace_session_snapshot_if_current(
            &self,
            runtime_id: &LogicalRuntimeId,
            expected_current: &[u8],
            replacement: Vec<u8>,
        ) -> Result<bool, meerkat_runtime::store::RuntimeStoreError> {
            if self.fail_snapshot_commits.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    "synthetic runtime snapshot commit failure".to_string(),
                ));
            }
            if self.fail_snapshot_replaces.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    "synthetic runtime snapshot replace failure".to_string(),
                ));
            }
            if let Some(interloper) = self
                .replace_snapshot_interlopers
                .lock()
                .await
                .remove(runtime_id)
            {
                self.inner
                    .commit_session_snapshot(
                        runtime_id,
                        SessionDelta {
                            session_snapshot: interloper,
                        },
                    )
                    .await?;
            }
            {
                let mut overrides = self.session_snapshot_overrides.lock().await;
                if let Some(current) = overrides.get_mut(runtime_id) {
                    if current.as_slice() != expected_current {
                        return Ok(false);
                    }
                    *current = replacement;
                    return Ok(true);
                }
            }
            self.inner
                .replace_session_snapshot_if_current(runtime_id, expected_current, replacement)
                .await
        }

        async fn clear_session_snapshot_if_current(
            &self,
            runtime_id: &LogicalRuntimeId,
            expected_current: &[u8],
        ) -> Result<bool, meerkat_runtime::store::RuntimeStoreError> {
            if let Some(interloper) = self
                .clear_snapshot_interlopers
                .lock()
                .await
                .remove(runtime_id)
            {
                self.inner
                    .commit_session_snapshot(
                        runtime_id,
                        SessionDelta {
                            session_snapshot: interloper,
                        },
                    )
                    .await?;
            }
            {
                let mut overrides = self.session_snapshot_overrides.lock().await;
                if let Some(current) = overrides.get(runtime_id) {
                    if current.as_slice() != expected_current {
                        return Ok(false);
                    }
                    overrides.remove(runtime_id);
                    return Ok(true);
                }
            }
            self.inner
                .clear_session_snapshot_if_current(runtime_id, expected_current)
                .await
        }

        async fn is_runtime_projection_quarantined(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<bool, meerkat_runtime::store::RuntimeStoreError> {
            self.inner
                .is_runtime_projection_quarantined(runtime_id)
                .await
        }

        async fn persist_input_state(
            &self,
            runtime_id: &LogicalRuntimeId,
            state: &InputStatePersistenceRecord,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            self.inner.persist_input_state(runtime_id, state).await
        }

        async fn load_input_state(
            &self,
            runtime_id: &LogicalRuntimeId,
            input_id: &InputId,
        ) -> Result<Option<StoredInputState>, meerkat_runtime::store::RuntimeStoreError> {
            self.inner.load_input_state(runtime_id, input_id).await
        }

        async fn load_machine_lifecycle_record(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<Option<Vec<u8>>, meerkat_runtime::store::RuntimeStoreError> {
            self.inner.load_machine_lifecycle_record(runtime_id).await
        }

        async fn commit_machine_lifecycle(
            &self,
            runtime_id: &LogicalRuntimeId,
            commit: meerkat_runtime::store::MachineLifecycleCommit,
            input_states: &[InputStatePersistenceRecord],
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            if self.fail_machine_lifecycle_commits.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    "synthetic machine lifecycle commit failure".to_string(),
                ));
            }
            self.inner
                .commit_machine_lifecycle(runtime_id, commit, input_states)
                .await
        }

        async fn commit_unregister_finalization(
            &self,
            runtime_id: &LogicalRuntimeId,
            finalization: meerkat_runtime::store::UnregisterFinalizationCommit,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            if self.fail_machine_lifecycle_commits.load(Ordering::Acquire) {
                return Err(meerkat_runtime::store::RuntimeStoreError::WriteFailed(
                    "synthetic machine lifecycle commit failure".to_string(),
                ));
            }
            self.inner
                .commit_unregister_finalization(runtime_id, finalization)
                .await
        }

        async fn persist_ops_lifecycle(
            &self,
            runtime_id: &LogicalRuntimeId,
            snapshot: &meerkat_runtime::ops_lifecycle::PersistedOpsSnapshot,
        ) -> Result<(), meerkat_runtime::store::RuntimeStoreError> {
            self.inner.persist_ops_lifecycle(runtime_id, snapshot).await
        }

        async fn initialize_ops_lifecycle_if_absent(
            &self,
            runtime_id: &LogicalRuntimeId,
            candidate: &meerkat_runtime::ops_lifecycle::PersistedOpsSnapshot,
        ) -> Result<
            meerkat_runtime::ops_lifecycle::PersistedOpsSnapshot,
            meerkat_runtime::store::RuntimeStoreError,
        > {
            self.inner
                .initialize_ops_lifecycle_if_absent(runtime_id, candidate)
                .await
        }

        async fn load_ops_lifecycle(
            &self,
            runtime_id: &LogicalRuntimeId,
        ) -> Result<
            Option<meerkat_runtime::ops_lifecycle::PersistedOpsSnapshot>,
            meerkat_runtime::store::RuntimeStoreError,
        > {
            self.inner.load_ops_lifecycle(runtime_id).await
        }
    }

    #[tokio::test]
    async fn runtime_snapshot_corruption_remains_typed_serialization() {
        let gated = Arc::new(GatedSnapshotRuntimeStore::new());
        let runtime_id = LogicalRuntimeId::for_session(&SessionId::new());
        gated
            .override_session_snapshot(runtime_id.clone(), b"{ not a serialized Session".to_vec())
            .await;
        let runtime_store: Arc<dyn RuntimeStore> = gated;

        let error = PersistentSessionService::<DummyBuilder>::load_runtime_session_snapshot(
            &runtime_store,
            &runtime_id,
        )
        .await
        .expect_err("malformed runtime snapshot bytes must fail decode");
        match error {
            SessionError::Store(source) => assert!(
                matches!(
                    source.downcast_ref::<SessionStoreError>(),
                    Some(SessionStoreError::Serialization(_))
                ),
                "malformed runtime snapshot bytes must remain a typed serialization error, got {source:?}"
            ),
            other => panic!("expected typed SessionError::Store, got {other:?}"),
        }
    }

    #[tokio::test]
    async fn runtime_snapshot_transport_failure_remains_internal_and_distinct() {
        let gated = Arc::new(GatedSnapshotRuntimeStore::new());
        gated.set_fail_snapshot_loads(true);
        let runtime_store: Arc<dyn RuntimeStore> = gated;
        let runtime_id = LogicalRuntimeId::for_session(&SessionId::new());

        let error = PersistentSessionService::<DummyBuilder>::load_runtime_session_snapshot(
            &runtime_store,
            &runtime_id,
        )
        .await
        .expect_err("transport failure must fail runtime snapshot load");
        assert!(
            matches!(error, SessionError::Agent(AgentError::InternalError(_))),
            "RuntimeStore transport failure must remain distinct from persisted serialization corruption, got {error:?}"
        );
    }

    #[tokio::test]
    async fn authoritative_read_preserves_typed_checkpoint_schema_error() {
        let store: Arc<dyn SessionStore> = Arc::new(MemoryStore::new());
        let runtime_store: Arc<dyn RuntimeStore> = Arc::new(InMemoryRuntimeStore::new());
        let session = Session::new();
        let id = session.id().clone();
        let (stamped, _) = with_checkpoint_root(session);
        let mut document = serde_json::to_value(stamped).expect("serialize stamped session");
        document["metadata"][meerkat_core::SESSION_CHECKPOINT_STAMP_KEY]["schema_version"] =
            serde_json::json!(u32::MAX);
        let unsupported: Session =
            serde_json::from_value(document).expect("Session keeps checkpoint evidence opaque");
        runtime_store
            .commit_session_snapshot(
                &LogicalRuntimeId::for_session(&id),
                SessionDelta {
                    session_snapshot: serde_json::to_vec(&unsupported)
                        .expect("serialize unsupported checkpoint fixture"),
                },
            )
            .await
            .expect("runtime snapshot should commit");
        let service = PersistentSessionService::new(
            DummyBuilder,
            4,
            store,
            runtime_store,
            memory_blob_store(),
        );

        let error = service
            .load_authoritative_session(&id)
            .await
            .expect_err("unsupported checkpoint schema must fail authoritative read");
        match error {
            SessionError::Store(source) => assert!(
                matches!(
                    source.downcast_ref::<meerkat_core::SessionCheckpointError>(),
                    Some(meerkat_core::SessionCheckpointError::UnsupportedSchemaVersion(version))
                        if *version == u32::MAX
                ),
                "unsupported checkpoint schema must remain typed, got {source:?}"
            ),
            other => panic!("expected typed SessionError::Store, got {other:?}"),
        }
    }

    #[test]
    fn conflicting_checkpoint_relation_remains_typed_authority_conflict() {
        let id = SessionId::new();
        let mut snapshot = Session::with_id(id.clone());
        snapshot.push(Message::User(UserMessage::text(
            "runtime branch".to_string(),
        )));
        let (snapshot, _) = with_checkpoint_root(snapshot);
        let mut store_head = Session::with_id(id.clone());
        store_head.push(Message::User(UserMessage::text("store branch".to_string())));
        let (store_head, _) = with_checkpoint_root(store_head);
        let service = PersistentSessionService::new(
            DummyBuilder,
            4,
            Arc::new(MemoryStore::new()),
            Arc::new(InMemoryRuntimeStore::new()),
            memory_blob_store(),
        );

        let error = service
            .resolve_runtime_snapshot_read_source(&id, snapshot, Some(store_head), false)
            .expect_err("conflicting checkpoint branches must fail read arbitration");
        match error {
            SessionError::Store(source) => assert!(
                matches!(
                    source.downcast_ref::<meerkat_core::SessionCheckpointError>(),
                    Some(meerkat_core::SessionCheckpointError::AuthorityBaseConflict(
                        _
                    ))
                ),
                "checkpoint relation conflict must remain typed, got {source:?}"
            ),
            other => panic!("expected typed SessionError::Store, got {other:?}"),
        }
    }

    #[test]
    fn committed_runtime_child_wins_over_intra_turn_sibling_from_same_typed_base() {
        let id = SessionId::new();
        let mut base = Session::with_id(id.clone());
        base.push(Message::User(UserMessage::text(
            "committed base".to_string(),
        )));
        let (base, base_stamp) = with_checkpoint_root(base);

        let mut runtime = base.clone();
        runtime.push(Message::User(UserMessage::text(
            "committed runtime child".to_string(),
        )));
        let (runtime, _) = with_checkpoint_successor(
            runtime,
            &base_stamp,
            meerkat_core::SessionCheckpointProvenance::RunBoundaryCommit,
        );

        let mut store_projection = base;
        store_projection.push(Message::User(UserMessage::text(
            "intra-turn store sibling".to_string(),
        )));
        let (store_projection, _) = with_checkpoint_successor(
            store_projection,
            &base_stamp,
            meerkat_core::SessionCheckpointProvenance::IntraTurnCheckpoint,
        );
        assert_eq!(
            meerkat_core::session_checkpoint_relation(&runtime, &store_projection)
                .expect("sibling relation should classify"),
            meerkat_core::SessionCheckpointRelation::RevisionConflict,
        );

        let service = PersistentSessionService::new(
            DummyBuilder,
            4,
            Arc::new(MemoryStore::new()),
            Arc::new(InMemoryRuntimeStore::new()),
            memory_blob_store(),
        );
        let selected = service
            .resolve_runtime_snapshot_read_source(
                &id,
                runtime.clone(),
                Some(store_projection),
                false,
            )
            .expect("committed runtime authority must beat its intra-turn sibling");
        assert_eq!(selected.messages(), runtime.messages());
        assert_eq!(
            verified_checkpoint_stamp(&selected),
            verified_checkpoint_stamp(&runtime),
        );
    }

