    #[tokio::test]
    async fn test_realtime_open_snapshot_synchronizes_stale_live_transcript_authority() {
        let store: Arc<dyn SessionStore> = Arc::new(MemoryStore::new());
        let runtime_store: Arc<dyn RuntimeStore> = Arc::new(InMemoryRuntimeStore::new());
        let service = PersistentSessionService::new(
            CapabilityBuilder,
            4,
            Arc::clone(&store),
            Arc::clone(&runtime_store),
            memory_blob_store(),
        );

        let created = service
            .create_session(create_request("seed", InitialTurnPolicy::Defer))
            .await
            .expect("create_session should succeed");
        assert!(
            service.comms_runtime(&created.session_id).await.is_some(),
            "test setup should install a live comms runtime"
        );

        let durable = service
            .export_live_session(&created.session_id)
            .await
            .expect("initial live session should export");
        let durable = mutate_with_test_checkpoint(
            durable,
            meerkat_core::SessionCheckpointProvenance::RunBoundaryCommit,
            |durable| {
                durable.push(Message::User(UserMessage::text(
                    "durable realtime seed".to_string(),
                )));
            },
        );
        runtime_store
            .commit_session_snapshot(
                &LogicalRuntimeId::for_session(&created.session_id),
                SessionDelta {
                    session_snapshot: serde_json::to_vec(&durable)
                        .expect("serialize durable session"),
                },
            )
            .await
            .expect("commit durable runtime snapshot");

        let live_export = service.export_live_session(&created.session_id).await;
        assert!(
            matches!(live_export, Err(SessionError::NotFound { .. })),
            "public live export must fail closed while durable semantic authority wins"
        );

        let realtime_snapshot = service
            .export_realtime_open_session_snapshot(&created.session_id)
            .await
            .expect("realtime open should use durable authority after syncing live mechanics");
        assert!(
            realtime_snapshot.messages().iter().any(|message| matches!(
                message,
                Message::User(user) if user.text_content() == "durable realtime seed"
            )),
            "realtime-open snapshot must be the durable semantic authority"
        );
        assert!(
            service
                .has_live_session(&created.session_id)
                .await
                .expect("live-session status should succeed"),
            "stale live transcript handle must remain installed after semantic sync"
        );
        assert!(
            service.comms_runtime(&created.session_id).await.is_some(),
            "semantic sync must preserve the live comms runtime"
        );
        assert!(
            service
                .interaction_event_injector(&created.session_id)
                .await
                .is_some(),
            "semantic sync must preserve the live interaction event injector"
        );
        let synced_live = service.export_live_session(&created.session_id).await;
        assert!(
            synced_live
                .expect("synced live session should export")
                .messages()
                .iter()
                .any(|message| matches!(
                    message,
                    Message::User(user) if user.text_content() == "durable realtime seed"
                )),
            "live session semantics must match the durable snapshot after realtime-open recovery"
        );
    }

    #[tokio::test]
    async fn test_realtime_open_snapshot_hydrates_durable_blob_backed_user_image() {
        let store: Arc<dyn SessionStore> = Arc::new(MemoryStore::new());
        let runtime_store: Arc<dyn RuntimeStore> = Arc::new(InMemoryRuntimeStore::new());
        let blob_store = Arc::new(MemoryBlobStore::new());
        let service_blob_store: Arc<dyn BlobStore> = blob_store.clone();
        let service = PersistentSessionService::new(
            CapabilityBuilder,
            4,
            Arc::clone(&store),
            Arc::clone(&runtime_store),
            service_blob_store,
        );

        let created = service
            .create_session(create_request("seed", InitialTurnPolicy::Defer))
            .await
            .expect("create_session should succeed");
        let image_data = "iVBORw0KGgoAAAANSUhEUgAAAAEAAAAB";
        let blob_ref = blob_store
            .put_image("image/png", image_data)
            .await
            .expect("image fixture should persist");
        let durable = service
            .export_live_session(&created.session_id)
            .await
            .expect("initial live session should export");
        let durable = mutate_with_test_checkpoint(
            durable,
            meerkat_core::SessionCheckpointProvenance::RunBoundaryCommit,
            |durable| {
                durable.push(Message::User(UserMessage::with_blocks(vec![
                    ContentBlock::Image {
                        media_type: "image/png".to_string(),
                        data: ImageData::Blob {
                            blob_id: blob_ref.blob_id.clone(),
                        },
                    },
                ])));
                durable.push(Message::ToolResults {
                    results: vec![ToolResult {
                        tool_use_id: "tool-image".to_string(),
                        content: vec![ContentBlock::Image {
                            media_type: "image/png".to_string(),
                            data: ImageData::Blob {
                                blob_id: blob_ref.blob_id.clone(),
                            },
                        }],
                        is_error: false,
                    }],
                    created_at: std::time::SystemTime::UNIX_EPOCH.into(),
                });
            },
        );
        runtime_store
            .commit_session_snapshot(
                &LogicalRuntimeId::for_session(&created.session_id),
                SessionDelta {
                    session_snapshot: serde_json::to_vec(&durable)
                        .expect("serialize durable image session"),
                },
            )
            .await
            .expect("commit durable runtime snapshot");

        let (realtime_snapshot, canonical_user_image_decoded_bytes) = service
            .export_realtime_open_session_snapshot_with_image_usage(&created.session_id)
            .await
            .expect("realtime provider projection should hydrate durable image bytes");
        assert_eq!(canonical_user_image_decoded_bytes, 24);
        assert!(matches!(
            realtime_snapshot.messages(),
            [Message::User(user), Message::ToolResults { results, .. }]
                if matches!(
                    user.content.as_slice(),
                    [ContentBlock::Image {
                        media_type,
                        data: ImageData::Inline { data },
                    }] if media_type == "image/png" && data == image_data
                )
                && matches!(
                    results.as_slice(),
                    [ToolResult { content, .. }]
                        if matches!(
                            content.as_slice(),
                            [ContentBlock::Image {
                                data: ImageData::Blob { blob_id },
                                ..
                            }] if blob_id == &blob_ref.blob_id
                        )
                )
        ));

        let synced_live = service
            .export_live_session(&created.session_id)
            .await
            .expect("durable authority should synchronize into the live handle");
        assert!(
            matches!(
                synced_live.messages(),
                [Message::User(user), Message::ToolResults { results, .. }]
                    if matches!(
                        user.content.as_slice(),
                        [ContentBlock::Image {
                            data: ImageData::Blob { blob_id },
                            ..
                        }] if blob_id == &blob_ref.blob_id
                    )
                    && matches!(
                        results.as_slice(),
                        [ToolResult { content, .. }]
                            if matches!(
                                content.as_slice(),
                                [ContentBlock::Image {
                                    data: ImageData::Blob { blob_id },
                                    ..
                                }] if blob_id == &blob_ref.blob_id
                            )
                    )
            ),
            "provider hydration must not rewrite canonical durable/live history inline"
        );
    }

