    #[tokio::test]
    async fn test_authoritative_read_preserves_malformed_rewrite_history_as_typed_corruption() {
        let store: Arc<dyn SessionStore> = Arc::new(MemoryStore::new());
        let runtime_store: Arc<dyn RuntimeStore> = Arc::new(InMemoryRuntimeStore::new());
        let event_store = Arc::new(RecordingEventStore::default());
        let event_store_trait: Arc<dyn EventStore> = event_store.clone();
        let projector_root = tempfile::tempdir().expect("projector tempdir");

        let session = recoverable_store_row();
        let id = session.id().clone();
        store.save(&session).await.expect("seed recoverable row");

        let parent_messages = Vec::new();
        let revision_messages = vec![Message::User(UserMessage::text("rewritten".to_string()))];
        let parent_revision = meerkat_core::transcript_messages_digest(&parent_messages)
            .expect("parent transcript digest");
        let revision = meerkat_core::transcript_messages_digest(&revision_messages)
            .expect("revision transcript digest");
        let record = meerkat_core::TranscriptRewriteRecord {
            commit: meerkat_core::TranscriptRewriteCommit {
                parent_revision: parent_revision.clone(),
                revision: revision.clone(),
                selection: TranscriptRewriteSelection::MessageRange { start: 0, end: 0 },
                original_span_digest: "forged-original-span".to_string(),
                replacement_digest: "forged-replacement-span".to_string(),
                messages_before: 0,
                messages_after: 1,
                reason: TranscriptRewriteReason::new("malformed-test"),
                actor: None,
                committed_at: meerkat_core::time_compat::SystemTime::now(),
            },
            parent_body: meerkat_core::TranscriptRevisionBody {
                revision: parent_revision.clone(),
                parent_revision: None,
                messages: parent_messages,
                created_at: meerkat_core::time_compat::SystemTime::now(),
            },
            revision_body: meerkat_core::TranscriptRevisionBody {
                revision,
                parent_revision: Some(parent_revision),
                messages: revision_messages,
                created_at: meerkat_core::time_compat::SystemTime::now(),
            },
        };
        event_store
            .append_envelopes(
                &id,
                &[meerkat_core::event::EventEnvelope::new_session(
                    id.clone(),
                    1,
                    None,
                    AgentEvent::TranscriptRewriteCommitted {
                        session_id: id.clone(),
                        record,
                    },
                )],
            )
            .await
            .expect("seed malformed durable rewrite record");

        let service = PersistentSessionService::new(
            DummyBuilder,
            4,
            store,
            runtime_store,
            memory_blob_store(),
        )
        .with_event_projection(
            event_store_trait,
            Arc::new(SessionProjector::new(projector_root.path().join(".rkat"))),
        );
        let error = service
            .load_authoritative_session(&id)
            .await
            .expect_err("malformed durable rewrite record must fail authoritative read");
        match error {
            SessionError::Store(source) => assert!(
                matches!(
                    source.downcast_ref::<SessionStoreError>(),
                    Some(SessionStoreError::Serialization(_))
                ),
                "malformed durable rewrite history must remain typed serialization corruption, got {source:?}"
            ),
            other => panic!("expected typed store corruption, got {other:?}"),
        }
    }

    /// Corrupt metadata under the reserved key is a read FAULT for the seam
    /// — `Err`, never `Ok(None)` (which would launder corruption into
    /// "no such session").
    #[tokio::test]
    async fn test_metadata_seam_corrupt_session_metadata_fails_closed() {
        let store: Arc<dyn SessionStore> = Arc::new(MemoryStore::new());
        let runtime_store: Arc<dyn RuntimeStore> = Arc::new(InMemoryRuntimeStore::new());
        let service = metadata_seam_service(&store, &runtime_store);

        let session = recoverable_store_row();
        let id = session.id().clone();
        let mut value = serde_json::to_value(&session).expect("session should serialize");
        value["metadata"][SESSION_METADATA_KEY] = serde_json::json!(42);
        let corrupt: Session =
            serde_json::from_value(value).expect("corrupt envelope should still deserialize");
        store.save(&corrupt).await.expect("seed corrupt store row");

        service
            .load_authoritative_session_metadata(&id)
            .await
            .expect_err("corrupt session_metadata must surface as Err, never Ok(None)");
    }

    /// Seam parity across present / absent / archived: filtering the seam
    /// through `session_archived_by_authority_with_terminal` yields exactly
    /// the visibility of the full-path `load_authoritative_session` +
    /// `session_archived_by_authority` composition (the persistent
    /// `MobSessionService::load_persisted_session` contract).
    #[tokio::test]
    async fn test_metadata_seam_visibility_parity_across_present_absent_archived() {
        let store: Arc<dyn SessionStore> = Arc::new(MemoryStore::new());
        let runtime_store: Arc<dyn RuntimeStore> = Arc::new(InMemoryRuntimeStore::new());
        let service = metadata_seam_service(&store, &runtime_store);

        // Present.
        let present = recoverable_store_row();
        let present_id = present.id().clone();
        store.save(&present).await.expect("seed present row");

        // Archived (legacy store-only archived shape).
        let archived = legacy_store_only_archived_row();
        let archived_id = archived.id().clone();
        store.save(&archived).await.expect("seed archived row");

        // Absent.
        let absent_id = SessionId::new();

        for (id, expected_visible) in [
            (&present_id, true),
            (&archived_id, false),
            (&absent_id, false),
        ] {
            let seam_visible = match service
                .load_authoritative_session_metadata(id)
                .await
                .expect("metadata seam load should succeed")
            {
                Some(view) => !service
                    .session_archived_by_authority_with_terminal(
                        id,
                        view.lifecycle_terminal.as_ref(),
                    )
                    .await
                    .expect("terminal archived read should succeed"),
                None => false,
            };
            let full_visible = match service
                .load_authoritative_session(id)
                .await
                .expect("full path load should succeed")
            {
                Some(session) => !service
                    .session_archived_by_authority(id, &session)
                    .await
                    .expect("full archived read should succeed"),
                None => false,
            };
            assert_eq!(
                seam_visible, full_visible,
                "seam visibility must match the full path for session {id}"
            );
            assert_eq!(
                seam_visible, expected_visible,
                "unexpected visibility for session {id}"
            );
        }
    }

